71	USING_YOSYS_NAMESPACE
72	
73	#if defined(YOSYS_ENABLE_READLINE) || defined(YOSYS_ENABLE_EDITLINE)
74	int yosys_history_offset = 0;
75	std::string yosys_history_file;
76	#endif
77	
78	void yosys_atexit()
79	{
80	#if defined(YOSYS_ENABLE_READLINE) || defined(YOSYS_ENABLE_EDITLINE)
81		if (!yosys_history_file.empty()) {
82	#if defined(YOSYS_ENABLE_READLINE)
83			if (yosys_history_offset > 0) {
84				history_truncate_file(yosys_history_file.c_str(), 100);
85				append_history(where_history() - yosys_history_offset, yosys_history_file.c_str());
86			} else
87				write_history(yosys_history_file.c_str());
88	#else
89			write_history(yosys_history_file.c_str());
90	#endif
91		}
92	
93		clear_history();
94	#if defined(YOSYS_ENABLE_READLINE)
95		HIST_ENTRY **hist_list = history_list();
96		if (hist_list != NULL)
97			free(hist_list);
98	#endif
99	#endif
100	}
101	
102	#if defined(__OpenBSD__)
103	namespace Yosys {
104	extern char *yosys_argv0;
105	extern char yosys_path[PATH_MAX];
106	};
107	#endif
108	#ifdef YOSYS_ENABLE_TCL
109	namespace Yosys {
110		extern int yosys_tcl_interp_init(Tcl_Interp *interp);
111		extern void yosys_tcl_activate_repl();
112	};
113	#endif
