115	int main(int argc, char **argv)
116	{
117		auto wall_clock_start = std::chrono::steady_clock::now();
118		std::string frontend_command = "auto";
119		std::string backend_command = "auto";
120		std::vector<std::string> vlog_defines;
121		std::vector<std::string> passes_commands;
122		std::vector<std::string> frontend_files;
123		std::vector<std::string> plugin_filenames;
124		std::vector<std::string> special_args;
125		std::string output_filename = "";
126		std::string scriptfile = "";
127		std::string depsfile = "";
128		std::string topmodule = "";
129		std::string perffile = "";
130		bool scriptfile_tcl = false;
131		bool scriptfile_python = false;
132		bool print_banner = true;
133		bool print_stats = true;
134		bool call_abort = false;
135		bool timing_details = false;
136		bool run_shell = true;
137		bool run_tcl_shell = false;
138		bool mode_v = false;
139		bool mode_q = false;
140	
141		cxxopts::Options options(argv[0], "Yosys Open SYnthesis Suite");
142		options.set_width(SIZE_MAX);
143	
144		options.add_options("operation")
145			("b,backend", "use <backend> for the output file specified on the command line",
146				cxxopts::value<std::string>(), "<backend>")
147			("f,frontend", "use <frontend> for the input files on the command line",
148				cxxopts::value<std::string>(), "<frontend>")
149			("s,scriptfile", "execute the commands in <scriptfile>",
150				cxxopts::value<std::string>(), "<scriptfile>")
151	#ifdef YOSYS_ENABLE_TCL
152			("c,tcl-scriptfile", "execute the commands in the TCL <tcl_scriptfile> (see 'help tcl' for details)",
153				cxxopts::value<std::string>(),"<tcl_scriptfile>")
154			("C,tcl-interactive", "enters TCL interactive shell mode")
155	#endif // YOSYS_ENABLE_TCL
156	#ifdef YOSYS_ENABLE_PYTHON
157			("y,py-scriptfile", "execute the Python <script>",
158				cxxopts::value<std::string>(), "<script>")
159	#endif // YOSYS_ENABLE_PYTHON
160			("p,commands", "execute <commands> (to chain commands, separate them with semicolon + whitespace: 'cmd1; cmd2')",
161				cxxopts::value<std::vector<std::string>>(), "<commands>")
162			("r,top", "elaborate the specified HDL <top> module",
163				cxxopts::value<std::string>(), "<top>")
164			("m,plugin", "load the specified <plugin> module",
165				cxxopts::value<std::vector<std::string>>(), "<plugin>")
166			("D,define", "set the specified Verilog define to <value> if supplied via command \"read -define\"",
167				cxxopts::value<std::vector<std::string>>(), "<define>[=<value>]")
168			("S,synth", "shortcut for calling the \"synth\" command, a default script for transforming " \
169						"the Verilog input to a gate-level netlist. For example: " \
170						"yosys -o output.blif -S input.v " \
171						"For more complex synthesis jobs it is recommended to use the read_* and write_* " \
172						"commands in a script file instead of specifying input and output files on the " \
173						"command line.")
174			("H", "print the command list")
175			("h,help", "print this help message. If given, print help for <command>.",
176				cxxopts::value<std::string>(), "[<command>]")
177			("V,version", "print version information and exit")
178			("git-hash", "print git commit hash and exit")
179			("infile", "input files", cxxopts::value<std::vector<std::string>>())
180		;
181		options.add_options("logging")
182			("Q", "suppress printing of banner (copyright, disclaimer, version)")
183			("T", "suppress printing of footer (log hash, version, timing statistics)")
184			("no-version", "suppress writing out Yosys version anywhere excluding -V, --version")
185			("q,quiet", "quiet operation. Only write warnings and error messages to console. " \
186						"Use this option twice to also quiet warning messages")
187			("v,verbose", "print log headers up to <level> to the console. " \
188	                      "Implies -q for everything except the 'End of script.' message.",
189				cxxopts::value<int>(), "<level>")
190			("t,timestamp", "annotate all log messages with a time stamp")
191			("d,detailed-timing", "print more detailed timing stats at exit")
192			("l,logfile", "write log messages to <logfile>",
193				cxxopts::value<std::vector<std::string>>(), "<logfile>")
194			("L,line-buffered-logfile", "like -l but open <logfile> in line buffered mode",
195				cxxopts::value<std::vector<std::string>>(), "<logfile>")
196			("o,outfile", "write the design to <outfile> on exit",
197				cxxopts::value<std::string>(), "<outfile>")
198			("P,dump-design", "dump the design when printing the specified log header to a file. " \
199							   "yosys_dump_<header_id>.il is used as filename if none is specified. " \
200							   "Use 'ALL' as <header_id> to dump at every header.",
201							   cxxopts::value<std::vector<std::string>>(), "<header_id>[:<filename>]")
202			("W,warning-as-warning", "print a warning for all log messages matching <regex>",
203				cxxopts::value<std::vector<std::string>>(), "<regex>")
204			("w,warning-as-message", "if a warning message matches <regex>, it is printed as regular message instead",
205				cxxopts::value<std::vector<std::string>>(), "<regex>")
206			("e,warning-as-error", "if a warning message matches <regex>, it is printed as error message instead",
207				cxxopts::value<std::vector<std::string>>(), "<regex>")
208			("E,deps-file", "write a Makefile dependencies file <depsfile> with input and output file names",
209				cxxopts::value<std::string>(), "<depsfile>")
210		;
211		options.add_options("developer")
212			("X,trace", "enable tracing of core data structure changes. for debugging")
213			("M,randomize-pointers", "will slightly randomize allocated pointer addresses. for debugging")
214			("autoidx", "start counting autoidx up from <seed>, similar effect to --hash-seed",
215				cxxopts::value<uint64_t>(), "<idx>")
216			("hash-seed", "mix up hashing values with <seed>, for extreme optimization and testing",
217				cxxopts::value<uint64_t>(), "<seed>")
218			("A,abort", "will call abort() at the end of the script. for debugging")
219			("x,experimental", "do not print warnings for the experimental <feature>",
220				cxxopts::value<std::vector<std::string>>(), "<feature>")
221			("g,debug", "globally enable debug log messages")
222			("perffile", "write a JSON performance log to <perffile>", cxxopts::value<std::string>(), "<perffile>")
223		;
224	
225		options.parse_positional({"infile"});
226		options.positional_help("[<infile> [..]]");
227	
228		// We can't have -h optionally require an argument
229		// cxxopts does have an implit argument concept but that doesn't work for us
230		// cxxopts is therefore instructed allowed to only handle the command help case
231		if (argc == 2 && (!strcmp(argv[1], "-h") || !strcmp(argv[1], "-help") || !strcmp(argv[1], "--help"))) {
232			std::cout << options.help() << std::endl;
233			exit(0);
234		}
235		try {
236			// Check for "--" in arguments
237			auto it = std::find(argv, argv + argc, std::string("--"));
238			if (it != argv + argc) {
239				special_args.assign(it + 1, argv + argc);
240				// Remove these arguments from cxxopts parsing
241				argc = std::distance(argv, it);
242			}
243	
244			auto result = options.parse(argc, argv);
245	
246			if (result.count("M")) memhasher_on();
247			if (result.count("X")) yosys_xtrace += result.count("X");
248			if (result.count("A")) call_abort = true;
249			if (result.count("Q")) print_banner = false;
250			if (result.count("T")) print_stats = false;
251			if (result.count("no-version")) yosys_write_versions = false;
252			if (result.count("V")) {
253				std::cout << yosys_version_str << std::endl;
254				exit(0);
255			}
256			if (result.count("git-hash")) {
257				std::cout << yosys_git_hash_str << std::endl;
258				exit(0);
259			}
260			if (result.count("S")) {
261				passes_commands.push_back("synth");
262				run_shell = false;
263			}
264			if (result.count("C")) run_tcl_shell = true;
265			if (result.count("g")) log_force_debug++;
266			if (result.count("m")) plugin_filenames = result["m"].as<std::vector<std::string>>();
267			if (result.count("f")) frontend_command = result["f"].as<std::string>();
268			if (result.count("H")) {
269				passes_commands.push_back("help");
270				run_shell = false;
271			}
272			if (result.count("h")) {
273				std::string res = result["h"].as<std::string>();
274				passes_commands.push_back("help " + res);
275				run_shell = false;
276			}
277			if (result.count("b")) {
278				backend_command = result["b"].as<std::string>();
279				run_shell = false;
280			}
281			if (result.count("p")) {
282				auto cmds = result["p"].as<std::vector<std::string>>();
283				passes_commands.insert(passes_commands.end(), cmds.begin(), cmds.end());
284				run_shell = false;
285			}
286			if (result.count("o")) {
287				output_filename = result["o"].as<std::string>();
288				run_shell = false;
289			}
290			for (const auto& key : {"l", "L"}) {
291				if (result.count(key)) {
292					for (const auto& filename : result[key].as<std::vector<std::string>>()) {
293						if (FILE* f = fopen(filename.c_str(), "wt")) {
294							log_files.push_back(f);
295							if (key[0] == 'L') setvbuf(f, NULL, _IOLBF, 0);
296						} else {
297							std::cerr << "Can't open log file `" << filename << "' for writing!\n";
298							exit(1);
299						}
300					}
301				}
302			}
303			if (result.count("q")) {
304				mode_q = true;
305				if (log_errfile == stderr) log_quiet_warnings = true;
306				log_errfile = stderr;
307			}
308			if (result.count("v")) {
309				mode_v = true;
310				log_errfile = stderr;
311				log_verbose_level = result["v"].as<int>();
312			}
313			if (result.count("t")) log_time = true;
314			if (result.count("d")) timing_details = true;
315			for (const auto& key : {"s", "c"}) {
316				if (result.count(key)) {
317					scriptfile = result[key].as<std::string>();
318					scriptfile_tcl = std::string(key) == "c";
319					run_shell = false;
320				}
321			}
322			if (result.count("y")) {
323				scriptfile = result["y"].as<std::string>();
324				scriptfile_python = true;
325				run_shell = false;
326			}
327			for (const auto& key : {"W", "w", "e"}) {
328				if (result.count(key)) {
329					auto regexes = result[key].as<std::vector<std::string>>();
330					for (const auto& regex : regexes) {
331						if (std::string(key) == "W")
332							log_warn_regexes.push_back(std::regex(regex));
333						if (std::string(key) == "w")
334							log_nowarn_regexes.push_back(std::regex(regex));
335						if (std::string(key) == "e")
336							log_werror_regexes.push_back(std::regex(regex));
337					}
338				}
339			}
340			if (result.count("r")) topmodule = result["r"].as<std::string>();
341			if (result.count("D")) vlog_defines = result["D"].as<std::vector<std::string>>();
342			if (result.count("P")) {
343				auto dump_args = result["P"].as<std::vector<std::string>>();
344				for (const auto& arg : dump_args) {
345					auto tokens = split_tokens(arg, ":");
346					if (!tokens.empty() && tokens[0] == "ALL") {
347						if (tokens.size() != 1) {
348							std::cerr << "Invalid number of tokens in -P ALL." << std::endl;
349							exit(1);
350						}
351						log_hdump_all = true;
352					} else {
353						if (!tokens.empty() && !tokens[0].empty() && tokens[0].back() == '.')
354							tokens[0].pop_back();
355						if (tokens.size() == 1)
356							tokens.push_back("yosys_dump_" + tokens[0] + ".il");
357						if (tokens.size() != 2) {
358							std::cerr << "Invalid number of tokens in -P." << std::endl;
359							exit(1);
360						}
361						log_hdump[tokens[0]].insert(tokens[1]);
362					}
363				}
364			}
365			if (result.count("E")) depsfile = result["E"].as<std::string>();
366			if (result.count("x")) {
367				auto ignores = result["x"].as<std::vector<std::string>>();
368				log_experimentals_ignored.insert(ignores.begin(), ignores.end());
369			}
370			if (result.count("perffile")) perffile = result["perffile"].as<std::string>();
371			if (result.count("infile")) {
372				frontend_files = result["infile"].as<std::vector<std::string>>();
373			}
374			if (result.count("autoidx")) {
375				int idx = result["autoidx"].as<uint64_t>();
376				autoidx = idx;
377			}
378			if (result.count("hash-seed")) {
379				int seed = result["hash-seed"].as<uint64_t>();
380				Hasher::set_fudge((Hasher::hash_t)seed);
381			}
382	
383			if (log_errfile == NULL) {
384				log_files.push_back(stdout);
385				log_error_stderr = true;
386			}
387	
388			if (print_banner)
389				yosys_banner();
390	
391		}
392		catch (const cxxopts::exceptions::parsing& e) {
393			std::cerr << "Error parsing options: " << e.what() << std::endl;
394			std::cerr << "Run '" << argv[0] << " --help' for help." << std::endl;
395			exit(1);
396		}
397	
398	#if defined(YOSYS_ENABLE_READLINE) || defined(YOSYS_ENABLE_EDITLINE)
399		std::string state_dir;
400		#if defined(_WIN32)
401			if (getenv("HOMEDRIVE") != NULL && getenv("HOMEPATH") != NULL) {
402				state_dir = stringf("%s%s/.local/state", getenv("HOMEDRIVE"), getenv("HOMEPATH"));
403			} else {
404				log_debug("$HOMEDRIVE and/or $HOMEPATH is empty. No history file will be created.\n");
405			}
406		#else
407			if (getenv("XDG_STATE_HOME") == NULL || getenv("XDG_STATE_HOME")[0] == '\0') {
408				if (getenv("HOME") != NULL) {
409					state_dir = stringf("%s/.local/state", getenv("HOME"));
410				} else {
411					log_debug("$HOME is empty. No history file will be created.\n");
412				}
413			} else {
414				state_dir = stringf("%s", getenv("XDG_STATE_HOME"));
415			}
416		#endif
417	
418		if (!state_dir.empty()) {
419			std::string yosys_dir = state_dir + "/yosys";
420			create_directory(yosys_dir);
421	
422			yosys_history_file = yosys_dir + "/history";
423			read_history(yosys_history_file.c_str());
424			yosys_history_offset = where_history();
425		}
426	#endif
427	
428		if (print_stats)
429			log_hasher = new SHA1;
430	
431	#if defined(__OpenBSD__)
432		// save the executable origin for proc_self_dirname()
433		yosys_argv0 = argv[0];
434		realpath(yosys_argv0, yosys_path);
435	#endif
436	
437	#if defined(__linux__)
438		// set stack size to >= 128 MB
439		{
440			struct rlimit rl;
441			const rlim_t stack_size = 128L * 1024L * 1024L;
442			if (getrlimit(RLIMIT_STACK, &rl) == 0 && rl.rlim_cur < stack_size) {
443				rl.rlim_cur = stack_size;
444				setrlimit(RLIMIT_STACK, &rl);
445			}
446		}
447	#endif
448	
449		yosys_setup();
450	#ifdef YOSYS_ENABLE_PYTHON
451		py::object sys = py::module_::import("sys");
452		sys.attr("path").attr("append")(proc_self_dirname());
453		sys.attr("path").attr("append")(proc_share_dirname());
454	#endif
455		log_error_atexit = yosys_atexit;
456	
457		for (auto &fn : plugin_filenames)
458			load_plugin(fn, {});
459	
460		log_suppressed();
461	
462		if (!vlog_defines.empty()) {
463			std::string vdef_cmd = "read -define";
464			for (auto vdef : vlog_defines)
465				vdef_cmd += " " + vdef;
466			run_pass(vdef_cmd);
467		}
468	
469		if (scriptfile.empty() || (!scriptfile_tcl && !scriptfile_python)) {
470			// Without a TCL or Python script, arguments following '--'
471			// are also treated as frontend files
472			for (auto special_arg : special_args)
473				frontend_files.push_back(special_arg);
474		}
475	
476		for (auto it = frontend_files.begin(); it != frontend_files.end(); ++it) {
477			if (run_frontend((*it).c_str(), frontend_command))
478				run_shell = false;
479		}
480	
481		if (!topmodule.empty())
482			run_pass("hierarchy -top " + topmodule);
483		if (!scriptfile.empty()) {
484			if (scriptfile_tcl) {
485	#ifdef YOSYS_ENABLE_TCL
486				int tcl_argc = special_args.size();
487				std::vector<Tcl_Obj*> script_args;
488				Tcl_Interp *interp = yosys_get_tcl_interp();
489				for (auto arg : special_args)
490					script_args.push_back(Tcl_NewStringObj(arg.c_str(), arg.length()));
491	
492				Tcl_ObjSetVar2(interp, Tcl_NewStringObj("argc", 4), NULL, Tcl_NewIntObj(tcl_argc), 0);
493				Tcl_ObjSetVar2(interp, Tcl_NewStringObj("argv", 4), NULL, Tcl_NewListObj(tcl_argc, script_args.data()), 0);
494				Tcl_ObjSetVar2(interp, Tcl_NewStringObj("argv0", 5), NULL, Tcl_NewStringObj(scriptfile.c_str(), scriptfile.length()), 0);
495	
496				if (Tcl_EvalFile(interp, scriptfile.c_str()) != TCL_OK)
497					log_error("TCL interpreter returned an error: %s\n", Tcl_GetStringResult(yosys_get_tcl_interp()));
498	#else
499				log_error("Can't execute TCL script: this version of yosys is not built with TCL support enabled.\n");
500	#endif
501			} else if (scriptfile_python) {
502	#ifdef YOSYS_ENABLE_PYTHON
503				py::list new_argv;
504				int py_argc = special_args.size() + 1;
505				new_argv.append(scriptfile);
506				for (int i = 1; i < py_argc; ++i)
507					new_argv.append(special_args[i - 1]);
508	
509				py::setattr(sys, "argv", new_argv);
510	
511				py::object Path = py::module_::import("pathlib").attr("Path");
512				py::object scriptfile_python_path = Path(scriptfile).attr("parent");
513	
514				sys.attr("path").attr("insert")(0, py::str(scriptfile_python_path));
515	
516				FILE *scriptfp = fopen(scriptfile.c_str(), "r");
517				if (scriptfp == nullptr) {
518					log_error("Failed to open file '%s' for reading.\n", scriptfile);
519				}
520				if (PyRun_SimpleFile(scriptfp, scriptfile.c_str()) != 0) {
521					log_flush();
522					PyErr_Print();
523					log_error("Python interpreter encountered an exception.");
524				}
525	#else
526				log_error("Can't execute Python script: this version of yosys is not built with Python support enabled.\n");
527	#endif
528			} else
529				run_frontend(scriptfile, "script");
530		}
531	
532		for (auto it = passes_commands.begin(); it != passes_commands.end(); it++)
533			run_pass(*it);
534	
535		if (run_tcl_shell) {
536	#ifdef YOSYS_ENABLE_TCL
537			yosys_tcl_activate_repl();
538			Tcl_Main(argc, argv, yosys_tcl_interp_init);
539	#else
540			log_error("Can't exectue TCL shell: this version of yosys is not built with TCL support enabled.\n");
541	#endif
542		} else {
543			if (run_shell)
544				shell(yosys_design);
545			else
546				run_backend(output_filename, backend_command);
547		}
548	
549		yosys_design->check();
550		for (auto it : saved_designs)
551			it.second->check();
552		for (auto it : pushed_designs)
553			it->check();
554	
555		if (!depsfile.empty())
556		{
557			FILE *f = fopen(depsfile.c_str(), "wt");
558			if (f == nullptr)
559				log_error("Can't open dependencies file for writing: %s\n", strerror(errno));
560			bool first = true;
561			for (auto fn : yosys_output_files) {
562				fprintf(f, "%s%s", first ? "" : " ", escape_filename_spaces(fn).c_str());
563				first = false;
564			}
565			fprintf(f, ":");
566			for (auto fn : yosys_input_files) {
567				if (yosys_output_files.count(fn) == 0)
568					fprintf(f, " %s", escape_filename_spaces(fn).c_str());
569			}
570			fprintf(f, "\n");
571		}
572	
573		if (log_expect_no_warnings && log_warnings_count_noexpect)
574			log_error("Unexpected warnings found: %d unique messages, %d total, %d expected\n", GetSize(log_warnings),
575						log_warnings_count, log_warnings_count - log_warnings_count_noexpect);
576	
577		if (print_stats)
578		{
579			std::string hash = log_hasher->final().substr(0, 10);
580			delete log_hasher;
581			log_hasher = nullptr;
582	
583			log_time = false;
584			yosys_xtrace = 0;
585			log_spacer();
586	
587			if (mode_v && !mode_q)
588				log_files.push_back(stderr);
589	
590			if (log_warnings_count)
591				log("Warnings: %d unique messages, %d total\n", GetSize(log_warnings), log_warnings_count);
592	
593			if (!log_experimentals.empty())
594				log("Warnings: %d experimental features used (not excluded with -x).\n", GetSize(log_experimentals));
595	
596	#ifdef _WIN32
597			log("End of script. Logfile hash: %s\n", hash);
598			(void)wall_clock_start;
599	#else
600			std::string meminfo;
601			std::string stats_divider = ", ";
602	
603			struct rusage ru_buffer;
604			getrusage(RUSAGE_SELF, &ru_buffer);
605			if (yosys_design->scratchpad_get_bool("print_stats.include_children")) {
606				struct rusage ru_buffer_children;
607				getrusage(RUSAGE_CHILDREN, &ru_buffer_children);
608				ru_buffer.ru_utime.tv_sec += ru_buffer_children.ru_utime.tv_sec;
609				ru_buffer.ru_utime.tv_usec += ru_buffer_children.ru_utime.tv_usec;
610				ru_buffer.ru_stime.tv_sec += ru_buffer_children.ru_stime.tv_sec;
611				ru_buffer.ru_stime.tv_usec += ru_buffer_children.ru_stime.tv_usec;
612	#if defined(__linux__) || defined(__FreeBSD__) || defined(__APPLE__)
613				ru_buffer.ru_maxrss = std::max(ru_buffer.ru_maxrss, ru_buffer_children.ru_maxrss);
614	#endif
615			}
616	#if defined(__linux__) || defined(__FreeBSD__)
617			meminfo = stringf(", MEM: %.2f MB peak",
618					ru_buffer.ru_maxrss / 1024.0);
619	#elif defined(__APPLE__)
620	// https://stackoverflow.com/questions/59913657/strange-values-of-get-rusage-maxrss-on-macos-and-linux
621			meminfo = stringf(", MEM: %.2f MB peak",
622					ru_buffer.ru_maxrss / (1024.0 * 1024.0));
623	#endif
624			double wall_seconds = std::chrono::duration<double>(
625					std::chrono::steady_clock::now() - wall_clock_start).count();
626	
627			log("End of script. Logfile hash: %s%stime: %.2fs, user: %.2fs, system: %.2fs%s\n", hash,
628					stats_divider.c_str(), wall_seconds, ru_buffer.ru_utime.tv_sec + 1e-6 * ru_buffer.ru_utime.tv_usec,
629					ru_buffer.ru_stime.tv_sec + 1e-6 * ru_buffer.ru_stime.tv_usec, meminfo.c_str());
630	#endif
631			log("%s\n", yosys_maybe_version());
632	
633			int64_t total_ns = 0;
634			std::set<tuple<int64_t, int, std::string>> timedat;
635	
636			for (auto &it : pass_register)
637				if (it.second->call_counter) {
638					auto pass_ns = it.second->runtime_ns + 1;
639					total_ns += pass_ns;
640					timedat.insert(make_tuple(pass_ns, it.second->call_counter, it.first));
641				}
642			{
643				auto gc_ns = RTLIL::OwningIdString::garbage_collection_ns() + 1;
644				total_ns += gc_ns;
645				timedat.insert(make_tuple(gc_ns,
646						RTLIL::OwningIdString::garbage_collection_count(), "id_gc"));
647			}
648	
649			if (timing_details)
650			{
651				log("Time spent:\n");
652				for (auto it = timedat.rbegin(); it != timedat.rend(); it++) {
653					log("%5d%% %5d calls %8.3f sec %s\n", int(100*std::get<0>(*it) / total_ns),
654							std::get<1>(*it), std::get<0>(*it) / 1000000000.0, std::get<2>(*it).c_str());
655				}
656			}
657			else
658			{
659				int out_count = 0;
660				log("Time spent:");
661				for (auto it = timedat.rbegin(); it != timedat.rend() && out_count < 4; it++, out_count++) {
662					if (out_count >= 2 && (std::get<0>(*it) < 1000000000 || int(100*std::get<0>(*it) / total_ns) < 20)) {
663						log(", ...");
664						break;
665					}
666					log("%s %d%% %dx %s (%d sec)", out_count ? "," : "", int(100*std::get<0>(*it) / total_ns),
667							std::get<1>(*it), std::get<2>(*it).c_str(), int(std::get<0>(*it) / 1000000000));
668				}
669				log("%s\n", out_count ? "" : " no commands executed");
670			}
671			if(!perffile.empty())
672			{
673				FILE *f = fopen(perffile.c_str(), "wt");
674				if (f == nullptr)
675					log_error("Can't open performance log file for writing: %s\n", strerror(errno));
676	
677				fprintf(f, "{\n");
678				fprintf(f, "  \"generator\": \"%s\",\n", yosys_maybe_version());
679				fprintf(f, "  \"total_ns\": %" PRIu64 ",\n", total_ns);
680				fprintf(f, "  \"passes\": {");
681	
682				bool first = true;
683				for (auto it = timedat.rbegin(); it != timedat.rend(); it++) {
684					if (!first)
685						fprintf(f, ",");
686					fprintf(f, "\n	\"%s\": {\n", std::get<2>(*it).c_str());
687					fprintf(f, "	  \"runtime_ns\": %" PRIu64 ",\n", std::get<0>(*it));
688					fprintf(f, "	  \"num_calls\": %u\n", std::get<1>(*it));
689					fprintf(f, "	}");
690					first = false;
691				}
692				fprintf(f, "\n  }\n}\n");
693			}
694		}
695	
696		log_check_expected();
697	
698		yosys_atexit();
699	
700		memhasher_off();
701		if (call_abort)
702			abort();
703	
704		log_flush();
705	#if defined(_MSC_VER)
706		_exit(0);
707	#elif defined(_WIN32)
708		_Exit(0);
709	#endif
710	
711		yosys_shutdown();
712	
713		return 0;
714	}
