723	bool run_frontend(std::string filename, std::string command, RTLIL::Design *design, std::string *from_to_label)
724	{
725		if (design == nullptr)
726			design = yosys_design;
727	
728		if (command == "auto") {
729		  std::string filename_trim = filename;
730	
731		  auto has_extension = [](const std::string& filename, const std::string& extension) {
732		    if (filename.size() >= extension.size()) {
733		      return filename.compare(filename.size() - extension.size(), extension.size(), extension) == 0;
734		    }
735		    return false;
736		  };
737	
738		  if (has_extension(filename_trim, ".gz")) {
739		    filename_trim.erase(filename_trim.size() - 3);
740		  }
741	
742		  if (has_extension(filename_trim, ".v")) {
743		    command = " -vlog2k";
744		  } else if (has_extension(filename_trim, ".sv")) {
745		    command = " -sv";
746		  } else if (has_extension(filename_trim, ".vhd") || has_extension(filename_trim, ".vhdl")) {
747		    command = " -vhdl";
748		  } else if (has_extension(filename_trim, ".blif") || has_extension(filename_trim, ".eblif")) {
749		    command = "blif";
750		  } else if (has_extension(filename_trim, ".json")) {
751		    command = "json";
